mapper.select:
SELECT t1.id, t1.task_id, t1.total_working_hours, t1.detection_type, t1.user_id, t1.user_name, t1.working_hours, t1.proportion, t2.order_time as create_time, t1.update_time, t2.state FROM test_task_order_working_hours AS t1 LEFT JOIN test_task AS t2 ON t1.task_id = t2.id LEFT JOIN test_report_record AS t4 ON t4.entrustment_id = t2.entrustment_id
1=1
and t1.user_id IN
#{id}
AND t4.issuer_time >= #{startDate}
AND #{stopDate} >= t4.issuer_time

SELECT sum(t1.working_hours) FROM test_task_order_working_hours AS t1 LEFT JOIN test_task AS t2 ON t1.task_id = t2.id LEFT JOIN test_report_record AS t4 ON t4.entrustment_id = t2.entrustment_id
1=1
and t1.user_id IN
#{id}
AND t4.issuer_time >= #{startDate}
AND #{stopDate} >= t4.issuer_time

SELECT t1.task_id, t1.total_working_hours AS working_hours, t1.task_code, t1.sample_name, t2.receiver AS user_id, t2.state, t2.end_detection_time AS createTime, t1.working_hours_id as workingHoursId FROM test_task_order_working_hours AS t1 LEFT JOIN test_task AS t2 ON t1.task_id = t2.id LEFT JOIN test_report_record AS t4 ON t4.entrustment_id = t2.entrustment_id WHERE t2.receiver = #{receiverUserId}
AND t4.issuer_time >= #{startDate}
AND #{stopDate} >= t4.issuer_time
GROUP BY CONCAT( t1.task_id, IFNULL( t1.working_hours_id, 0 ) )

SELECT * FROM test_task_order_working_hours WHERE task_id in
#{id}
GROUP BY CONCAT( task_id, IFNULL( working_hours_id, 0 ) )

SELECT t1.* FROM test_task_order_working_hours AS t1 LEFT JOIN test_task AS t2 ON t1.task_id = t2.id LEFT JOIN test_report_record AS t4 ON t4.entrustment_id = t2.entrustment_id WHERE 1 = 1 and t1.user_id = #{receiverUserId}
AND t4.issuer_time >= #{startDate}
AND #{stopDate} >= t4.issuer_time
